import { Link } from 'react-router-dom';
import workspace1 from '../images/austin-distel-wawEfYdpkag-unsplash.jpg';
import workspace2 from '../images/infralist-com-kmIKEGO7Vl4-unsplash.jpg';
import workspace3 from '../images/uneebo-office-design-UgYT5nkXdK4-unsplash.jpg';
import workspace4 from '../images/pawel-chu-ULh0i2txBCY-unsplash.jpg';
import workspace5 from '../images/suryadhityas-NrDZJ9oWV_Y-unsplash.jpg';
import workspace6 from '../images/running-a-successful-coworking-space-5aaa98c0bb414814ce745dc8.jpg';

const workspaceImages = [workspace1, workspace2, workspace3, workspace4, workspace5, workspace6];

export default function SpaceCard({ space, onToggleFavorite, isFavorite, commuteMins }) {
  // Handle both _id (MongoDB) and id (mock data)
  const spaceId = space._id || space.id;
  // Use space ID to consistently pick an image
  const imageIndex = (spaceId ? String(spaceId).length : 0) % workspaceImages.length;
  const spaceImage = space.images?.[0] || workspaceImages[imageIndex];

  return (
    <Link
      to={`/spaces/${spaceId}`}
      className="group block bg-white/90 dark:bg-gray-800/90 backdrop-blur-xl rounded-3xl overflow-hidden shadow-xl hover:shadow-2xl transition-all duration-500 border border-gray-200/50 dark:border-gray-700/50 hover:border-purple-300 dark:hover:border-purple-500 hover:-translate-y-2"
    >
      {/* Image Section */}
      <div className="relative h-72 overflow-hidden">
        <img
          src={spaceImage}
          alt={space.name}
          className="w-full h-full object-cover group-hover:scale-125 transition-transform duration-700"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-purple-900/80 via-pink-900/40 to-transparent group-hover:from-purple-900/90 group-hover:via-pink-900/50 transition-all duration-500"></div>

        {/* Rating Badge */}
        <div className="absolute top-5 left-5">
          <div className="px-4 py-2 bg-white/95 dark:bg-gray-900/95 backdrop-blur-xl rounded-xl shadow-xl flex items-center gap-2 border border-white/20">
            <svg className="w-5 h-5 text-yellow-400 fill-current" viewBox="0 0 20 20">
              <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
            </svg>
            <span className="text-sm font-bold text-gray-900 dark:text-white">{space.rating || '4.5'}</span>
          </div>
        </div>

        {/* Price Badge */}
        <div className="absolute bottom-5 right-5">
          <div className="px-5 py-3 bg-gradient-to-br from-purple-600 to-pink-600 rounded-xl shadow-2xl border border-white/20">
            <div className="text-white font-extrabold text-xl">₹{space.pricePerDay}</div>
            <div className="text-purple-100 text-xs font-semibold">/day</div>
          </div>
        </div>
      </div>

      {/* Content Section */}
      <div className="p-7">
        <h3 className="text-2xl font-extrabold text-gray-900 dark:text-white mb-3 group-hover:text-purple-600 dark:group-hover:text-purple-400 transition-colors line-clamp-1">
          {space.name}
        </h3>

        <div className="flex items-center gap-2 text-sm text-gray-600 dark:text-gray-400 mb-5">
          <svg className="w-5 h-5 text-purple-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" />
          </svg>
          <span className="line-clamp-1 font-medium">{space.locationText || space.city}</span>
        </div>

        {typeof commuteMins === 'number' && (
          <div className="mb-5 inline-flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-green-50 to-emerald-50 dark:from-green-900/30 dark:to-emerald-900/30 border border-green-200 dark:border-green-800 rounded-xl">
            <svg className="w-5 h-5 text-green-600 dark:text-green-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
            </svg>
            <span className="text-xs font-bold text-green-700 dark:text-green-400">~{commuteMins} min away</span>
          </div>
        )}

        <div className="flex flex-wrap gap-2 mb-5">
          {space.amenities?.slice(0, 2).map((amenity, idx) => (
            <span
              key={idx}
              className="text-xs px-3 py-1.5 bg-gradient-to-r from-purple-50 to-pink-50 dark:from-purple-900/20 dark:to-pink-900/20 text-purple-700 dark:text-purple-300 font-semibold rounded-lg border border-purple-200 dark:border-purple-800"
            >
              {amenity}
            </span>
          ))}
          {space.amenities?.length > 2 && (
            <span className="text-xs px-3 py-1.5 bg-gradient-to-r from-purple-600 to-pink-600 text-white font-bold rounded-lg shadow-lg">
              +{space.amenities.length - 2} more
            </span>
          )}
        </div>

        {onToggleFavorite && (
          <button
            type="button"
            className={`w-full py-4 rounded-xl font-bold transition-all duration-300 flex items-center justify-center gap-2 ${isFavorite
                ? 'bg-gradient-to-r from-purple-600 to-pink-600 text-white hover:shadow-glow'
                : 'bg-gradient-to-r from-gray-100 to-gray-200 dark:from-gray-700 dark:to-gray-600 text-gray-700 dark:text-gray-300 hover:from-purple-50 hover:to-pink-50 dark:hover:from-purple-900/20 dark:hover:to-pink-900/20'
              }`}
            onClick={(e) => {
              e.preventDefault();
              e.stopPropagation();
              onToggleFavorite(spaceId);
            }}
          >
            {isFavorite ? (
              <>
                <svg className="w-5 h-5 fill-current" viewBox="0 0 20 20">
                  <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
                </svg>
                Saved
              </>
            ) : (
              <>
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.915c.969 0 1.371 1.24.588 1.81l-3.976 2.888a1 1 0 00-.363 1.118l1.518 4.674c.3.922-.755 1.688-1.538 1.118l-3.976-2.888a1 1 0 00-1.176 0l-3.976 2.888c-.783.57-1.838-.197-1.538-1.118l1.518-4.674a1 1 0 00-.363-1.118l-3.976-2.888c-.784-.57-.38-1.81.588-1.81h4.914a1 1 0 00.951-.69l1.519-4.674z" />
                </svg>
                Save
              </>
            )}
          </button>
        )}
      </div>
    </Link>
  );
}
